# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.

Allowlist valid hosts/paths and validate universal link parameters before navigation or privileged actions.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    
    enum LinkDestination {
        case profile(userId: String)
        case paymentConfirm
        case adminSettings
        case invalid
    }
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedPaths = [
        "/profile/",
        "/payment/confirm",
        "/admin/settings"
    ]
    
    func handleUniversalLink(_ url: URL) -> LinkDestination {
        guard isValidHost(url) else {
            return .invalid
        }
        
        guard isValidPath(url) else {
            return .invalid
        }
        
        return parseDestination(from: url)
    }
    
    private func isValidHost(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased() else {
            return false
        }
        return allowedHosts.contains(host)
    }
    
    private func isValidPath(_ url: URL) -> Bool {
        let path = url.path
        
        for allowedPath in allowedPaths {
            if path == allowedPath || path.hasPrefix(allowedPath) {
                return true
            }
        }
        
        return false
    }
    
    private func parseDestination(from url: URL) -> LinkDestination {
        let path = url.path
        let components = path.split(separator: "/").map(String.init)
        
        if components.count >= 2 && components[0] == "profile" {
            let userId = components[1]
            if isValidUserId(userId) {
                return .profile(userId: userId)
            }
            return .invalid
        }
        
        if path == "/payment/confirm" {
            return .paymentConfirm
        }
        
        if path == "/admin/settings" {
            return .adminSettings
        }
        
        return .invalid
    }
    
    private func isValidUserId(_ userId: String) -> Bool {
        let allowedCharacters = CharacterSet.alphanumerics
        let userIdCharacterSet = CharacterSet(charactersIn: userId)
        
        guard allowedCharacters.isSuperset(of: userIdCharacterSet) else {
            return false
        }
        
        guard userId.count > 0 && userId.count <= 50 else {
            return false
        }
        
        return true
    }
}

class AppCoordinator {
    
    private let linkHandler = UniversalLinkHandler()
    private weak var navigationController: UINavigationController?
    
    init(navigationController: UINavigationController) {
        self.navigationController = navigationController
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        let destination = linkHandler.handleUniversalLink(url)
        
        switch destination {
        case .profile(let userId):
            navigateToProfile(userId: userId)
            return true
            
        case .paymentConfirm:
            navigateToPaymentConfirm()
            return true
            
        case .adminSettings:
            navigateToAdminSettings()
            return true
            
        case .invalid:
            return false
        }
    }
    
    private func navigateToProfile(userId: String) {
        let profileVC = ProfileViewController()
        profileVC.userId = userId
        navigationController?.pushViewController(profileVC, animated: true)
    }
    
    private func navigateToPaymentConfirm() {
        let paymentVC = PaymentConfirmViewController()
        navigationController?.pushViewController(paymentVC, animated: true)
    }
    
    private func navigateToAdminSettings() {
        guard hasAdminPrivileges() else {
            showUnauthorizedAlert()
            return
        }
        
        let adminVC = AdminSettingsViewController()
        navigationController?.pushViewController(adminVC, animated: true)
    }
    
    private func hasAdminPrivileges() -> Bool {
        return UserSession.shared.isAdmin
    }
    
    private func showUnauthorizedAlert() {
        let alert = UIAlertController(
            title: "Unauthorized",
            message: "You don't have permission to access this section.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController?.present(alert, animated: true)
    }
}

