extension SceneDelegate {
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return
        }
        
        handleUniversalLink(incomingURL)
    }
    
    private func handleUniversalLink(_ url: URL) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first,
              let navigationController = window.rootViewController as? UINavigationController else {
            return
        }
        
        let coordinator = AppCoordinator(navigationController: navigationController)
        let handled = coordinator.handleUniversalLink(url)
        
        if !handled {
            showInvalidLinkAlert(in: navigationController)
        }
    }
    
    private func showInvalidLinkAlert(in navigationController: UINavigationController) {
        let alert = UIAlertController(
            title: "Invalid Link",
            message: "The link you followed is not valid or has expired.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController.present(alert, animated: true)
    }
}

extension AppDelegate {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }
        
        return handleUniversalLink(incomingURL)
    }
    
    private func handleUniversalLink(_ url: URL) -> Bool {
        guard let window = UIApplication.shared.windows.first,
              let navigationController = window.rootViewController as? UINavigationController else {
            return false
